#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

#define MAX_LINE_LENGTH 256
#define MAX_SENSORS 100

// ============================================
// STRUCTURES FOR SENSOR DATA
// ============================================

typedef struct {
    char timestamp[32];
    char sensor_id[16];
    float temperature;
    float humidity;
    float pressure;
} SensorReading;

typedef struct {
    char device_id[32];
    char location[64];
    int sampling_rate;
    float temp_threshold_min;
    float temp_threshold_max;
} DeviceConfig;

// ============================================
// FILE OPERATIONS
// ============================================

// Append sensor reading to log file
void append_to_log(const char *filename, SensorReading *reading) {
    FILE *file = fopen(filename, "a");
    if (file == NULL) {
        printf("Error: Could not open file %s\n", filename);
        return;
    }

    fprintf(file, "%s,%s,%.2f,%.2f,%.2f\n", 
            reading->timestamp, 
            reading->sensor_id,
            reading->temperature, 
            reading->humidity,
            reading->pressure);

    fclose(file);
    printf("Reading logged successfully\n");
}

// Read and display log file contents
void read_log_file(const char *filename) {
    FILE *file = fopen(filename, "r");
    if (file == NULL) {
        printf("Error: Could not open file %s\n", filename);
        return;
    }

    char line[MAX_LINE_LENGTH];
    printf("\n=== Sensor Log Contents ===\n");

    // Read header line
    if (fgets(line, sizeof(line), file) != NULL) {
        printf("Header: %s", line);
    }

    // Read data lines
    while (fgets(line, sizeof(line), file) != NULL) {
        printf("%s", line);
    }

    fclose(file);
}

// ============================================
// CSV-LIKE FILE OPERATIONS
// ============================================

// Write sensor data to CSV file
void write_sensor_csv(const char *filename, SensorReading *readings, int count) {
    FILE *file = fopen(filename, "w");
    if (file == NULL) {
        printf("Error: Could not create file %s\n", filename);
        return;
    }

    // Write CSV header
    fprintf(file, "Timestamp,Sensor_ID,Temperature,Humidity,Pressure\n");

    // Write data rows
    for (int i = 0; i < count; i++) {
        fprintf(file, "%s,%s,%.2f,%.2f,%.2f\n",
                readings[i].timestamp,
                readings[i].sensor_id,
                readings[i].temperature,
                readings[i].humidity,
                readings[i].pressure);
    }

    fclose(file);
    printf("CSV file written with %d readings\n", count);
}

// Read sensor data from CSV file
int read_sensor_csv(const char *filename, SensorReading *readings) {
    FILE *file = fopen(filename, "r");
    if (file == NULL) {
        printf("Error: Could not open file %s\n", filename);
        return -1;
    }

    char line[MAX_LINE_LENGTH];
    int count = 0;

    // Skip header line
    fgets(line, sizeof(line), file);

    // Read data lines
    while (fgets(line, sizeof(line), file) != NULL && count < MAX_SENSORS) {
        sscanf(line, "%[^,],%[^,],%f,%f,%f",
               readings[count].timestamp,
               readings[count].sensor_id,
               &readings[count].temperature,
               &readings[count].humidity,
               &readings[count].pressure);
        count++;
    }

    fclose(file);
    return count;
}

// ============================================
// CONFIGURATION FILE OPERATIONS
// ============================================

// Save device configuration to file
void save_config(const char *filename, DeviceConfig *config) {
    FILE *file = fopen(filename, "w");
    if (file == NULL) {
        printf("Error: Could not create config file\n");
        return;
    }

    fprintf(file, "device_id=%s\n", config->device_id);
    fprintf(file, "location=%s\n", config->location);
    fprintf(file, "sampling_rate=%d\n", config->sampling_rate);
    fprintf(file, "temp_threshold_min=%.1f\n", config->temp_threshold_min);
    fprintf(file, "temp_threshold_max=%.1f\n", config->temp_threshold_max);

    fclose(file);
    printf("Configuration saved to %s\n", filename);
}

// Load device configuration from file
int load_config(const char *filename, DeviceConfig *config) {
    FILE *file = fopen(filename, "r");
    if (file == NULL) {
        printf("Error: Could not open config file\n");
        return -1;
    }

    char line[MAX_LINE_LENGTH];
    while (fgets(line, sizeof(line), file) != NULL) {
        char key[64], value[128];
        sscanf(line, "%[^=]=%s", key, value);

        if (strcmp(key, "device_id") == 0) {
            strcpy(config->device_id, value);
        } else if (strcmp(key, "location") == 0) {
            strcpy(config->location, value);
        } else if (strcmp(key, "sampling_rate") == 0) {
            config->sampling_rate = atoi(value);
        } else if (strcmp(key, "temp_threshold_min") == 0) {
            config->temp_threshold_min = atof(value);
        } else if (strcmp(key, "temp_threshold_max") == 0) {
            config->temp_threshold_max = atof(value);
        }
    }

    fclose(file);
    return 0;
}

// ============================================
// UTILITY FUNCTIONS
// ============================================

// Get current timestamp as string
void get_timestamp(char *buffer, size_t size) {
    time_t now = time(NULL);
    struct tm *tm_info = localtime(&now);
    strftime(buffer, size, "%Y-%m-%d %H:%M:%S", tm_info);
}

// Check if temperature exceeds threshold
void check_thresholds(SensorReading *reading, DeviceConfig *config) {
    if (reading->temperature > config->temp_threshold_max) {
        printf("ALERT: High temperature! %.2f > %.2f\n", 
               reading->temperature, config->temp_threshold_max);
    } else if (reading->temperature < config->temp_threshold_min) {
        printf("ALERT: Low temperature! %.2f < %.2f\n", 
               reading->temperature, config->temp_threshold_min);
    }
}

// ============================================
// MAIN DEMONSTRATION
// ============================================

int main() {
    printf("=== C File Handling for IoT ===\n\n");

    // Example 1: Append sensor readings to log file
    printf("--- Append to Log File ---\n");
    SensorReading reading1;
    get_timestamp(reading1.timestamp, sizeof(reading1.timestamp));
    strcpy(reading1.sensor_id, "TEMP_01");
    reading1.temperature = 24.5;
    reading1.humidity = 65.2;
    reading1.pressure = 1013.0;
    append_to_log("sensor_log.csv", &reading1);

    // Add second reading
    get_timestamp(reading1.timestamp, sizeof(reading1.timestamp));
    reading1.temperature = 25.0;
    reading1.humidity = 64.8;
    append_to_log("sensor_log.csv", &reading1);

    // Example 2: Write and read CSV file
    printf("\n--- CSV File Operations ---\n");
    SensorReading readings[3];

    strcpy(readings[0].timestamp, "2024-02-09 10:00:00");
    strcpy(readings[0].sensor_id, "TEMP_01");
    readings[0].temperature = 23.5;
    readings[0].humidity = 65.2;
    readings[0].pressure = 1013.0;

    strcpy(readings[1].timestamp, "2024-02-09 10:05:00");
    strcpy(readings[1].sensor_id, "TEMP_01");
    readings[1].temperature = 24.1;
    readings[1].humidity = 64.8;
    readings[1].pressure = 1012.0;

    strcpy(readings[2].timestamp, "2024-02-09 10:10:00");
    strcpy(readings[2].sensor_id, "TEMP_02");
    readings[2].temperature = 22.9;
    readings[2].humidity = 66.1;
    readings[2].pressure = 1014.0;

    write_sensor_csv("sensor_data.csv", readings, 3);

    // Read back the CSV
    SensorReading loaded_readings[MAX_SENSORS];
    int count = read_sensor_csv("sensor_data.csv", loaded_readings);
    printf("Loaded %d readings from CSV\n", count);
    for (int i = 0; i < count; i++) {
        printf("  %s: %.2fC, %.2f%%\n", 
               loaded_readings[i].sensor_id,
               loaded_readings[i].temperature,
               loaded_readings[i].humidity);
    }

    // Example 3: Configuration file operations
    printf("\n--- Configuration File ---\n");
    DeviceConfig config;
    strcpy(config.device_id, "IOT_SENSOR_001");
    strcpy(config.location, "Building A, Floor 2");
    config.sampling_rate = 60;
    config.temp_threshold_min = 15.0;
    config.temp_threshold_max = 30.0;

    save_config("device_config.txt", &config);

    // Load and display config
    DeviceConfig loaded_config;
    load_config("device_config.txt", &loaded_config);
    printf("Loaded: Device=%s, Location=%s, Rate=%ds\n",
           loaded_config.device_id,
           loaded_config.location,
           loaded_config.sampling_rate);

    // Example 4: Threshold checking
    printf("\n--- Threshold Checking ---\n");
    check_thresholds(&readings[0], &config);  // 23.5 - OK
    readings[1].temperature = 32.0;  // High!
    check_thresholds(&readings[1], &config);  // Alert!

    printf("\n=== Program Complete ===\n");
    return 0;
}
